function getVesselIcon(typeId) {
  if (typeId >= 0 && typeId <= 19) { return "🛥️";}
	const icon = iconMap[typeId];
	if (!icon) {
		console.warn(`iconMap: unbekannte typeId → ${typeId}`);
		return "❓";
	}
	return icon;
}
